// Drop administrative databases of common managed PostgreSQL services
// (AWS RDS, GCP Cloud SQL, Azure Database for PostgreSQL). These exist
// only to support the platform and are never user data.
//
// Additional databases can be skipped via the custom attribute
// Template.PostgreSQL.SkipDatabases on the node or template - a
// comma-separated list of regex patterns matched against the database
// name (each pattern is anchored ^...$).
//
// Example:  Template.PostgreSQL.SkipDatabases = postgres,repmgr,.*_shadow

dbname = $1.left($1.indexOf("@"));
if (dbname in ["rdsadmin", "cloudsqladmin", "azure_maintenance", "azure_sys"])
   return null;

attr = $object.getCustomAttribute("Template.PostgreSQL.SkipDatabases");
if (attr != null)
{
   for(p : attr.split(",", true))
   {
      pattern = "^" .. p .. "$";
      if (p != "" && dbname ~= pattern)
         return null;
   }
}
return $1;

