filter.source:
if (classof($object) != "Node")
   return false;
if (!$node.isAgent)
   return false;
servers = $node.readAgentList("PostgreSQL.DBServers");
return servers != null && servers.size > 0;

if (classof($object) != "Node")
   return false;
if (!$node.isAgent)
   return false;
if (!($node.platformName like "Linux-*"))
   return false;
count = $node.readAgentParameter("Process.Count(postgres)");
return count != null && count != "0";

if (classof($object) != "Node")
   return false;
if (!$node.isAgent)
   return false;
if (!($node.platformName like "windows-*"))
   return false;
count = $node.readAgentParameter("Process.Count(postgres.exe)");
return count != null && count != "0";
